"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[432],{7432:(i,a,e)=>{e.r(a),e.d(a,{default:()=>o});let o={locale:"it",langName:"Italiano",nav:{allPrograms:"Tutti i programmi",howItWorks:"Come funziona",about:"Sulla guida",applyNow:"Candidati ora →",officialPortal:"Portale ufficiale →"},hero:{pill:"Per i giovani dai 18 ai 35 anni",line1:"Fai qualcosa che",line2:"conti davvero",sub:"L'UE finanzia il volontariato, i viaggi in treno, i tirocini retribuiti e il supporto all'occupazione per i giovani europei. Tutte le informazioni in un unico posto — semplice e senza burocrazia.",cta1:"Inizia →",cta2:"Scopri di pi\xf9"},stats:[{value:"11",label:"Programmi UE coperti"},{value:"16 mln+",label:"Partecipanti Erasmus+ dal 1987"},{value:"40 000",label:"Pass DiscoverEU per ciclo"},{value:"0 €",label:"Costo per candidarsi"}],home:{what:{label:"Cos'\xe8 questo?",heading:"L'UE paga — tu scegli come contribuire",body:"L'Unione Europea offre un'ampia gamma di programmi finanziati per i giovani: volontariato all'estero, viaggi in treno gratuiti in Europa, tirocini retribuiti presso le istituzioni UE, supporto all'occupazione e servizi informativi. Questa guida raccoglie tutti i programmi in un unico luogo — con informazioni concrete sui requisiti, su cosa \xe8 coperto e su come candidarsi. Nessuna burocrazia. Solo fatti."},programs:{label:"Programmi dell'UE",heading:"Scegli il tuo percorso"},howItWorks:{label:"Passo dopo passo",heading:"Come iniziare",steps:[{title:"Scegli il tuo programma",desc:"Sfoglia i programmi qui sotto. Filtra per categoria: volontariato, tirocinio, viaggio o lavoro."},{title:"Informati bene",desc:"Ogni programma ha la sua pagina dedicata con informazioni complete su requisiti, cosa \xe8 coperto e come candidarsi."},{title:"Candidati tramite il portale ufficiale",desc:"Ogni programma rimanda direttamente al portale ufficiale di candidatura dell'UE. Le candidature sono sempre gratuite."}]},quickPicks:{label:"Trova quello giusto",heading:"Quale programma fa per te?",items:[{icon:"\uD83E\uDD1D",title:"Voglio fare volontariato all'estero",desc:"Il CES finanzia il volontariato fino a 12 mesi. Alloggio, vitto, viaggi e indennit\xe0 mensile inclusi. Nessuna esperienza richiesta.",cta:"Al CES →",slug:"europeiska-solidaritetskaren"},{icon:"\uD83C\uDF0D",title:"Voglio fare lavoro umanitario fuori dall'UE",desc:"Il ramo umanitario del CES ti invia in paesi terzi — protezione dei rifugiati, risposta alle catastrofi, clima. Formazione obbligatoria.",cta:"Al volontariato umanitario →",slug:"humanitart-volontararbete"},{icon:"\uD83D\uDE86",title:"Compio 18 anni e voglio viaggiare per l'Europa",desc:"DiscoverEU ti offre un abbonamento ferroviario gratuito con 7 giorni di viaggio. 40 000 pass per ciclo, selezione tramite quiz UE.",cta:"A DiscoverEU →",slug:"discovereu"},{icon:"\uD83D\uDCCB",title:"Sono laureato e voglio fare tirocinio all'UE",desc:"Blue Book (Commissione, 1 538 €/mese) e il tirocinio Schuman (Parlamento, fino a 2 257 €/mese) offrono placement retribuiti di 5 mesi.",cta:"Al Blue Book →",slug:"blue-book-traineeship"},{icon:"\uD83D\uDCBC",title:"Voglio lavorare in un altro paese UE",desc:"EURES ha 3 milioni di offerte di lavoro e consulenza gratuita in 31 paesi. EURES TMS offre sostegno finanziario per viaggi e corsi di lingua.",cta:"A EURES →",slug:"eures"},{icon:"\uD83D\uDD0D",title:"Non so esattamente cosa sto cercando",desc:"Eurodesk \xe8 la rete di informazione giovanile dell'UE con oltre 200 programmi nel suo database. Inizia da l\xec per una panoramica completa.",cta:"A Eurodesk →",slug:"eurodesk"}]},faq:{label:"Domande frequenti",heading:"Risposte alle tue domande",items:[{q:"Devo pagare qualcosa per partecipare ai programmi dell'UE?",a:"No. I programmi di volontariato dell'UE (CES), DiscoverEU e i servizi informativi come EURES e Eurodesk sono gratuiti. I programmi di tirocinio retribuito (Blue Book e Schuman) pagano te — non il contrario."},{q:"Ho bisogno della cittadinanza UE per partecipare?",a:"La maggior parte dei programmi \xe8 aperta ai cittadini dei 27 stati membri dell'UE pi\xf9 alcuni paesi associati (Islanda, Liechtenstein, Norvegia, Macedonia del Nord, Turchia, Serbia). Alcuni programmi, come EURES, sono aperti anche a chiunque risieda legalmente in tali paesi."},{q:"Quanti anni devo avere?",a:"Dipende dal programma. Volontariato CES: 18-30 anni. Volontariato umanitario: 18-35 anni. DiscoverEU: esattamente 18 anni. EURES: 18+ senza limite superiore di et\xe0. Blue Book e Schuman: laureati senza limite superiore di et\xe0 indicato."},{q:"Dove trovo le candidature ufficiali?",a:"La pagina di ogni programma in questa guida rimanda direttamente al portale ufficiale di candidatura. Tutte le candidature vengono effettuate tramite le piattaforme proprie dell'UE — non tramite questo sito."},{q:"Quanto sono affidabili le informazioni di questo sito?",a:"Le informazioni si basano sui siti web ufficiali dell'UE. Tieni presente che le scadenze e gli importi possono cambiare — controlla sempre le fonti ufficiali collegate sulla pagina di ogni programma."}]},about:{label:"Sulla guida",heading:"Una guida non ufficiale e indipendente",p1:"Questa guida \xe8 stata creata per condividere informazioni sulle opportunit\xe0 dell'UE in modo semplice e senza burocrazia. La fonte principale \xe8 un documento compilato in modo rigoroso, basato esclusivamente sui siti web ufficiali dell'UE: youth.europa.eu, commission.europa.eu, eacea.ec.europa.eu, erasmus-plus.ec.europa.eu e eures.europa.eu.",p2:"Questo sito web \xe8 non ufficiale e non \xe8 affiliato all'Unione Europea o a nessuna delle sue istituzioni. Le informazioni ufficiali e giuridicamente vincolanti sono sempre disponibili sul sito web della rispettiva istituzione dell'UE."},cta:{heading:"Pronto a fare il grande passo?",sub:"Scegli un programma e candidati direttamente sul portale ufficiale dell'UE — gratuitamente.",btn1:"Sfoglia i programmi →",btn2:"Portale europeo della giovent\xf9 ↗"}},filter:{all:"Tutti i programmi",volontär:"\uD83E\uDD1D Volontariato",utbildning:"\uD83C\uDF93 Istruzione",resa:"\uD83D\uDE86 Viaggi",praktik:"\uD83D\uDCCB Tirocini",jobb:"\uD83D\uDCBC Lavoro",info:"ℹ️ Informazioni"},programPage:{back:"Tutti i programmi",applyOfficially:"Candidati ufficialmente →",howItWorks:"Come funziona",sections:{what:"Cos'\xe8?",areas:"Aree di attivit\xe0",areasHeading:"Con cosa puoi lavorare?",areasExplore:"Esplora tutte le aree →",areasNote:"Oltre a queste sei aree principali, esistono progetti CES nel benessere animale, nella preparazione alle catastrofi, nella democrazia, nei diritti umani, nello sport e molto altro. Nessuna esperienza richiesta.",opportunities:"Opportunit\xe0",opportunitiesHeading:"Scegli il tuo percorso",covered:"Sostegno finanziario",coveredHeading:"Cosa copre l'UE",steps:"Passo dopo passo",stepsHeading:"Come funziona",faq:"Domande frequenti",faqHeading:"Risposte alle tue domande"},cta:{heading:"Pronto a candidarti?",btn1:"Vai al portale ufficiale →",btn2:"← Tutti i programmi"},related:{label:"Programmi correlati",heading:"Potrebbe interessarti anche"},checkmark:"✓"},areasPage:{back:"← Torna al CES",allAreas:"← Tutte le aree",overviewLabel:"Panoramica",examplesLabel:"Attivit\xe0",examplesHeading:"Cosa fai davvero",skillsLabel:"Competenze",skillsHeading:"Cosa sviluppi",suitedForLabel:"Per te che",suitedForHeading:"Questa area fa per te se...",practicalLabel:"Pratico",practicalHeading:"Informazioni pratiche",practicalDuration:"Durata",practicalLanguages:"Lingue",practicalRequirements:"Requisiti",applyESK:"Cerca progetti CES →",backToProgram:"← Torna al CES",relatedLabel:"Altre aree",relatedHeading:"Esplora altre aree",indexLabel:"Aree di attivit\xe0",indexHeading:"Sei aree — scegli il tuo ambito",indexSub:"Il Corpo Europeo di Solidariet\xe0 copre molti campi. Ecco i sei pi\xf9 comuni — clicca per leggere cosa comporta davvero il lavoro.",indexNote:"Oltre a queste, esistono progetti CES sul benessere animale, la preparazione alle catastrofi, la democrazia, i diritti umani, lo sport e molto altro."},footer:{tagline:"Una guida non ufficiale sulle opportunit\xe0 finanziate dall'UE per i giovani.",disclaimer:"Fonte principale: siti web ufficiali dell'UE (youth.europa.eu, commission.europa.eu, erasmus-plus.ec.europa.eu, eures.europa.eu, european-union.europa.eu).",programs:"Programmi",sources:"Fonti ufficiali",unofficial:"Una guida non ufficiale. Le informazioni ufficiali sono sempre disponibili sul sito web della rispettiva istituzione dell'UE.",date:"Informazioni aggiornate a maggio 2026. Verifica sempre le fonti ufficiali per le scadenze correnti.",cofunded:"Cofinanziato dall'Unione Europea"}}}}]);